            if name in skip:
                continue
            if hasattr(value, "value"):
                value = value.value
            try:
                constexpr_type = self._infer_constexpr_type(value)
            except ValueError:
                continue
            constexprs[name] = {"type": constexpr_type, "value": value}
        return constexprs

